from flask import request
import ldap

@app.route("/normal")
def normal():
    dc = request.args.get('dc')
    username = request.args.get('username')
    if not dc or not username:
        return "Missing parameters", 400
    base_dn = f"dc={dc}"
    filter_str = f"(uid={ldap.filter.escape_filter_string(username)})"
    try:
        ldap_conn = ldap.initialize('ldap://localhost:389')
        ldap_conn.bind()
        result = ldap_conn.search_s(base_dn, ldap.SCOPE_SUBTREE, filter_str)
        return str(result)
    except ldap.LDAPError as e:
        return str(e), 500
    finally:
        if 'ldap_conn' in locals():
            ldap_conn.unbind()

from flask import request, Flask
import ldap3

app = Flask(__name__)

@app.route("/normal")
def normal():
    dc = request.args.get('dc')
    username = request.args.get('username')
    if not dc or not username:
        return 'Missing parameters', 400
    base_dn = 'dc=' + ldap3.utils.conv.escape_filter_chars(dc)
    server = ldap3.Server('localhost', port=389, use_ssl=False)
    conn = ldap3.Connection(server, auto_bind=True)
    try:
        conn.search(base_dn, f'(uid={ldap3.utils.conv.escape_filter_chars(username)})', search_scope=ldap3.SUBTREE)
        return str(conn.response)
    except ldap3.LDAPException as e:
        return str(e), 500

